def generate_cache_key(prefix, *args, **kwargs):
    key_data = f"{prefix}:{':'.join(str(arg) for arg in args)}"
    if kwargs:
        key_data += f":{':'.join(f'{k}={v}' for k, v in sorted(kwargs.items()))}"
    return hashlib.md5(key_data.encode()).hexdigest()

def cache_get(key):
    try:
        return memcache_client.get(key)
    except Exception as e:
        print(f"Cache get error: {e}")
        return None

def cache_set(key, value, ttl=300):
    try:
        memcache_client.set(key, value, expire=ttl)
    except Exception as e:
        print(f"Cache set error: {e}")

def cache_delete(key):
    try:
        memcache_client.delete(key)
    except Exception as e:
        print(f"Cache delete error: {e}")

def cache_flush():
    try:
        memcache_client.flush_all()
    except Exception as e:
        print(f"Cache flush error: {e}")

@app.route('/users', methods=['GET'])
def get_users():
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 10, type=int)
    
    cache_key = generate_cache_key('users', page=page, per_page=per_page)
    
    cached_data = cache_get(cache_key)
    if cached_data:
        return jsonify({
            'data': cached_data,
            'cached': True,
            'timestamp': datetime.utcnow().isoformat()
        })
    
    conn = get_db_connection()
    offset = (page - 1) * per_page
    users = conn.execute(
        'SELECT * FROM users LIMIT ? OFFSET ?',
        (per_page, offset)
    ).fetchall()
    conn.close()
    
    users_list = [dict(user) for user in users]
    
    cache_set(cache_key, users_list, ttl=300)
    
    return jsonify({
        'data': users_list,
        'cached': False,
        'timestamp': datetime.utcnow().isoformat()
    })

